INSERT INTO majors (major_id, code, name, description, sort_order) VALUES
(1,'SCHOOL','대학원 진학형','대학원 진학을 희망하는 학생들을 위한 커리큘럼',1),
(2,'BIGDATA','빅데이터분야','데이터분석 전문가, 데이터 활용에 대해 배우고 싶은 학생들을 위한 커리큘럼',2),
(3,'AICLOUD','AI/클라우드분야','AI와 클라우드에 대해 심도있는 학습을 하고싶은 학생들을 위한 커리큘럼',3),
