INSERT INTO courses (course_id, code, name, description, year, semester, credit, is_required) VALUES
                                                                                                  (1,'cr101','빅데이터 분석기초','데이터 분석의 기초 원리와 기법을 소개한다. 데이터 수집, 정제, 분석 및 결과 해석의 전 과정에 대해 학습한다',1,1,3,TRUE),
                                                                                                  (2,'cr102','객체지향 프로그래밍','본 과정은 자바언어를 이용하여 각종 응용프로그램을 작성하고 실행해봄으로써 객체지향의 개념을 이해한다.',1,1,3,FALSE),
                                                                                                  (3,'cr103','인공지능개론','본 과목에서는 인공지능의 기본 개념 및 관련 용어, 문제 해결을 위한 지식표현, 추론방법 및 다양한 검색기법, 그리고 기계학습 기법에 대하여 학습한다',1,2,3,TRUE),
                                                                                                  (4,'cr104','미적분학','본 과목은 인공지능 동작원리를 이해하기 위한 높은 진입장벽을 낮추고 인공지능 기술을 이해할 수 있는 핵심적인 수학적 도구들을 소개한다.',1,2,3,FALSE),
